export default{
	data() {
		return {
			mode:false,
		}
	},
	props:{
		items:{
			type:Array,
			default:[]
		},
		types:{
			type:String,
			default:'single'
		}
	},
	methods:{
		cancel(){
			this.mode = false
		},
		show(){
			this.mode =true;
		},
		comfirm(){
			this.mode = false
			let data={
				types:this.types,
				item:this.items
			}
			this.$emit('comfirm',data)
		},
		moveHandle(){
			
		},
		checkboxChange(e) {
		var items = this.items;
		let values = e.detail.value;
		for (var i = 0, lenI = items.length; i < lenI; ++i) {
			items[i].checked = false;
			for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
				if (items[i].value == values[j]) {
					items[i].checked = true;
					break;
				}
			}
		}
	},
	}
}
